  "architecture": {
    "components": [
      { "name": "Logistics API", "responsibility": "Orchestrates shipment quoting, booking, and payment across external services", "boundaries": "Owns request lifecycle, routing, and response assembly" },
      { "name": "Geocoding Service (External)", "responsibility": "Resolves addresses to coordinates for distance/zone calculation", "boundaries": "Third-party API, outside operational control" },
      { "name": "Carrier Rates API (External)", "responsibility": "Provides shipping rate quotes from carriers", "boundaries": "Third-party API, outside operational control" },
      { "name": "Payment Gateway (External)", "responsibility": "Processes payments for shipments", "boundaries": "Third-party API, outside operational control" },
      { "name": "Database", "responsibility": "Persists orders, shipments, and transactional data", "boundaries": "Internal, query times reported normal" }
    ],
    "interfaces": [
      { "from": "Logistics API", "to": "Geocoding Service", "contract": "HTTP REST — address in, coordinates out", "coupling_type": "temporal (synchronous)" },
      { "from": "Logistics API", "to": "Carrier Rates API", "contract": "HTTP REST — origin/dest/weight in, rates out", "coupling_type": "temporal (synchronous)" },
      { "from": "Logistics API", "to": "Payment Gateway", "contract": "HTTP REST — payment details in, confirmation out", "coupling_type": "temporal (synchronous)" },
      { "from": "Logistics API", "to": "Database", "contract": "SQL queries via connection pool", "coupling_type": "temporal (synchronous)" }
    ],
    "data_flow": "Inbound request → geocoding lookup → carrier rate fetch → (optional) payment processing → database write → response. If calls are sequential, total latency = sum of all external call latencies + DB + internal processing. At 10K req/day (~0.12 RPS avg), throughput is low — this is not a load problem, it is a per-request latency problem.",
    "patterns_used": []
  },

  "domain_model": {
    "bounded_contexts": [
      { "name": "Shipment Quoting", "classification": "core", "aggregates": ["Quote", "Route"] },
      { "name": "Payment Processing", "classification": "supporting", "aggregates": ["Payment", "Transaction"] },
      { "name": "Address Resolution", "classification": "generic", "aggregates": [] }
    ],
    "context_map": [
      { "upstream": "Geocoding Service", "downstream": "Logistics API", "relationship": "Conformist — API consumes external model as-is" },
      { "upstream": "Carrier Rates API", "downstream": "Logistics API", "relationship": "Conformist — rate structures dictated by carrier" },
      { "upstream": "Payment Gateway", "downstream": "Logistics API", "relationship": "Customer-Supplier — gateway provides SDK/contract" }
    ]
  },

  "trade_offs": [
    {
      "decision": "Synchronous sequential calls to three external APIs",
      "gains": "Simple request flow, easy to reason about, transactional consistency",
      "sacrifices": "Total latency is additive — any single slow dependency inflates overall P99. No isolation between external service degradation and user experience.",
      "alternatives_considered": ["Parallel external calls where independent", "Async with webhooks for payment", "Pre-fetching/caching geocoding and rates"]
    }
  ],

  "flexibility_points": [
    { "area": "Geocoding results", "evolution_path": "Highly cacheable — addresses rarely change coordinates. Introducing a cache here could eliminate one external call entirely for repeated addresses." },
    { "area": "Carrier rate queries", "evolution_path": "Rates are often stable for hours/days. A short-TTL cache or background refresh pattern could absorb rate API degradation." },
    { "area": "External call orchestration", "evolution_path": "Geocoding and carrier rate lookups are likely independent and can be parallelized. Payment must remain sequential." }
  ],

  "rigidity_points": [
    { "area": "Synchronous external API coupling", "reason": "Without timeouts, circuit breakers, or fallbacks, the service's latency is hostage to the slowest external dependency." },
    { "area": "Lack of per-dependency observability", "reason": "Team reports DB looks normal but has no visibility into individual external API call durations — a critical observability gap." }
  ],

  "risks": [
    {
      "risk": "HYPOTHESIS 1 (MOST LIKELY): One or more external APIs have degraded. The gradual increase strongly suggests a downstream service experiencing its own scaling issues or degradation. At P99, even a small percentage of slow responses from an external API compounds when three are called sequentially. The geocoding or carrier rates API are prime suspects — payment gateway degradation would more likely produce errors.",
      "severity": "critical",
      "mitigation": "Instrument per-dependency call latency immediately (add timers around each external HTTP call). Compare histograms over the two-week window. Add timeouts (e.g., 500ms per call), circuit breakers, and fallback behavior."
    },
    {
      "risk": "HYPOTHESIS 2 (LIKELY): Cache expiration or degradation. If the service previously cached geocoding results or carrier rates, and the cache was silently lost (Redis eviction policy change, memory pressure, TTL misconfiguration), every request now makes live external calls. This would produce exactly this symptom: gradual increase as cache hit rate declines, no errors, no deployment correlation.",
      "severity": "high",
      "mitigation": "Check cache hit/miss ratios if caching exists. If no caching exists, this is a key architectural gap to address. Verify Redis/Memcached memory and eviction metrics."
    },
